const update = $input.first().json;
const msg = update.message || {};

return [{
 json: {
 telegram_chat_id: String(msg.chat?.id || ''),
 telegram_message_id: String(msg.message_id || ''),
 text: msg.text || '',
 raw_text: msg.text || '',
 source_type: msg.voice ? 'voice' : 'text',
 has_voice: !!msg.voice,
 voice_file_id: msg.voice?.file_id || null
 }
}];

return [{
 json: {
 ...$json,
 transcript: '[VOICE TRANSCRIPT HERE]',
 raw_text: '[VOICE TRANSCRIPT HERE]'
 }
}];

const transcript = $json.transcript;

const systemPrompt = `Ти AI parser.

Поверни ТІЛЬКИ JSON.
Без markdown.
Без пояснень.

Формат:
{
 "type":"expense|task|meeting|reminder|note",
 "title":"string",
 "amount":number|null,
 "currency":"UAH|USD|EUR|null",
 "person":"string|null",
 "project":"string|null",
 "event_datetime":"ISO8601|null",
 "due_datetime":"ISO8601|null",
 "status":"open|done|scheduled",
 "metadata":{}
}`;

return [{
 json: {
 ...$json,
 requestBody: {
 model: 'openai/gpt-4o-mini',
 temperature: 0.1,
 messages: [
 {
 role: 'system',
 content: systemPrompt
 },
 {
 role: 'user',
 content: transcript
 }
 ]
 }
 }
}];

const response = $json;
const original = $('Prepare OpenRouter').first().json;

try {

 const content = response.choices[0].message.content;
 const parsed = JSON.parse(content);

 return [{
 json: {
 success: true,
 parsed,
 original
 }
 }];

} catch (e) {

 return [{
 json: {
 success: false,
 error: e.message,
 original
 }
 }];

}

const parsed = $('Parse JSON').first().json.parsed;
const original = $('Parse JSON').first().json.original;

return [{
 json: {
 telegram_chat_id: original.telegram_chat_id,
 text: `✅ Подію збережено\n\nТип: ${parsed.type}\nНазва: ${parsed.title}`
 }
}];
